 1	import * as React from 'react';
 2	import { GraphEmpty } from '@odf/shared/charts';
 3	import { PrometheusMultilineUtilizationItem } from '@odf/shared/dashboards/utilization-card/prometheus-multi-utilization-item';
 4	import {
 5	  useCustomPrometheusPoll,
 6	  usePrometheusBasePath,
 7	} from '@odf/shared/hooks/custom-prometheus-poll';
 8	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 9	import { humanizeDecimalBytesPerSec } from '@odf/shared/utils';
10	import { PrometheusResult } from '@openshift-console/dynamic-plugin-sdk';
11	import { UtilizationDurationDropdown } from '@openshift-console/dynamic-plugin-sdk-internal';
12	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
13	import {
14	  NFS_TOPK_CLIENT_THROUGHPUT_TOTAL,
15	  NFSDashboardQuery,
16	  nfsPerClientReadWriteThroughputTotal,
17	  NFSOperation,
18	} from '../../../queries';
19	
20	export const TopClientsCard: React.FC = () => {
21	  const { t } = useCustomTranslation();
22	  const [topClients, topClientsError, topClientsLoading] =
23	    useCustomPrometheusPoll({
24	      endpoint: 'api/v1/query' as any,
25	      query:
26	        NFS_TOPK_CLIENT_THROUGHPUT_TOTAL[NFSDashboardQuery.TOPK_CLIENT_TOTAL],
27	      basePath: usePrometheusBasePath(),
28	    });
29	
30	  const clientNames: string[] = React.useMemo(
31	    () =>
32	      !topClientsLoading && !topClientsError
33	        ? topClients?.data?.result?.map(
34	            (item: PrometheusResult) => item?.metric?.client
35	          )
36	        : [],
37	    [topClients, topClientsError, topClientsLoading]
38	  );
39	
40	  return (
41	    <Card data-test="nfs-details-card">
42	      <CardHeader
43	        actions={{
44	          actions: <UtilizationDurationDropdown />,
45	          hasNoOffset: false,
46	          className: undefined,
47	        }}
48	      >
49	        <CardTitle>{t('Top clients')}</CardTitle>
50	      </CardHeader>
51	      <CardBody>
52	        {!!clientNames.length &&
53	          clientNames.map((clientName) => (
54	            <PrometheusMultilineUtilizationItem
55	              title={t('Client: {{ clientName }}', { clientName })}
56	              queries={[
57	                nfsPerClientReadWriteThroughputTotal(
58	                  clientName,
59	                  NFSOperation.READ
60	                ),
61	                nfsPerClientReadWriteThroughputTotal(
62	                  clientName,
63	                  NFSOperation.WRITE
64	                ),
65	              ]}
66	              humanizeValue={humanizeDecimalBytesPerSec}
67	              chartType="stacked-area"
68	              key={clientName}
69	            />
70	          ))}
71	        {!clientNames.length && (
72	          <GraphEmpty loading={topClientsLoading && !topClientsError} />
73	        )}
74	      </CardBody>
75	    </Card>
76	  );
77	};

